import * as React from 'react';
import { useState } from 'react';
import type { Required } from 'utility-types';
import { useControlledState } from '@universe-design/react-utilities';
import { useEventCallback } from '../../hooks';
import { isFunction } from '../../util';
import type { InternalSelectOptionConfig, InternalSelectProps, SelectValue } from '../internal.interface';

export function useSelectOverlayVisible<V extends SelectValue, OP extends InternalSelectOptionConfig<V>>({
  disabled,
  defaultOpen,
  open,
  onDropdownVisibleChange: onDropdownVisibleChangeProp,
  setInputting,
}: Required<
  Pick<InternalSelectProps<V, OP>, 'onDropdownVisibleChange' | 'disabled' | 'defaultOpen' | 'open'>,
  'disabled' | 'defaultOpen'
> & {
  setInputting: React.Dispatch<boolean>;
}) {
  const onDropdownVisibleChange = useEventCallback(_open => {
    // 不使用 _open 而是使用 dropdown 实际的 visible 状态来控制 inputting，以避免用户通过 open 参数手动控制 dropdown 状态时 inputting 存在的问题
    // if (!_open) {
    //    setInputting(false);
    // }
    if (isFunction(onDropdownVisibleChangeProp)) {
      onDropdownVisibleChangeProp(_open);
    }
  });

  const [overlayVisible, _setOverlayVisible] = useControlledState(defaultOpen, open, {
    onChange: onDropdownVisibleChange,
  });

  const setOverlayVisible = React.useCallback(
    (visible?: boolean) => {
      // console.trace(visible);
      if (disabled) {
        return;
      }
      if (visible !== undefined) {
        _setOverlayVisible(visible);
      } else {
        _setOverlayVisible(v => !v);
      }
    },
    [_setOverlayVisible, disabled],
  );

  // 使用 overlayVisible 控制 inputting。文档链接: https://bytedance.feishu.cn/wiki/wikcnARs8OQgxMMwA499n5hnTFg#doxcn6skUC0qaugmmK1rPT1boDv
  const [prevVisible, setPrevVisible] = useState<boolean>();

  if (overlayVisible !== prevVisible) {
    setInputting(overlayVisible);
    setPrevVisible(overlayVisible);
  }

  return {
    overlayVisible,
    setOverlayVisible,
  };
}
